import { mapState } from "vuex";
export default {
  props: {
    summoner: Object
  },
  methods: {
    openChatWindow() {
      this.$store.dispatch("setPrivateChatOpen", this.summoner).then(didOpen => {
        this.$sound.template("OVERVIEW_CLICK");
        if (didOpen) {
          this.$socket.sendSystemMessage("MESSAGE_PRIVATE_GET", {
            data: this.summoner
          }, (response, error) => {
            if (error) {
              console.log("Flyback error:");
              console.log(error);
            } else {
              this.$store.dispatch("setPrivateChatReadMessages", this.summoner);
            }
          });
        }
      });
    },
    showContextMenu(event) {
      const positioning = `top: ${event.clientY}px;left: ${event.clientX - 150}px`;
      const params = {
        friend: this.summoner,
        positioning: positioning
      };
      this.$modal.friendcontextmenu.show(params);
    },
    formatStatus(status, motto) {
      switch (status) {
        case "ONLINE":
          return motto ? motto : this.$translate.text(`FRO_STATUS_${status}`);
        case "AWAY":
          return motto ? motto : this.$translate.text(`FRO_STATUS_${status}`);
        default:
          return this.$translate.text(`FRO_STATUS_${status}`);
      }
    }
  },
  computed: mapState({
    unreadChatMessages(state) {
      if (state.privateChat.chatMessages[this.summoner.summonerName]) {
        let unread = 0;
        state.privateChat.chatMessages[this.summoner.summonerName].forEach(message => {
          if (message.read === false) {
            unread++;
          }
        });
        return unread;
      } else {
        return 0;
      }
    }
  })
};
